1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface DamageEntry {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface ClaimStep {
18	  op: "claim";
19	  policy: number;
20	  incident: {
21	    cause: string;
22	    damages: DamageEntry[];
23	  };
24	}
25	
26	type Step = QuoteStep | ClaimStep;
27	
28	interface Scenario {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Step[];
31	}
32	
33	type QuoteResult = { premium: number };
34	type ClaimResult = { payout: number };
35	type StepResult = QuoteResult | ClaimResult;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  amulet: 60,
39	  sword: 100,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUM));
47	
48	const FIRST_INSURANCE_RATE = 0.1;
49	const PROCESSING_FEE = 5;
50	
51	const CURSE_SURCHARGE_RATE = 0.5;
52	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
53	const HIGH_ENCHANTMENT_THRESHOLD = 5;
54	const LOYALTY_DISCOUNT_RATE = 0.2;
55	const LOYALTY_THRESHOLD_YEARS = 2;
56	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
57	
58	// Component-block pricing: 3 alike components of the same type (e.g. 3 runes
59	// or 3 moonstones) sold together are priced as a 60 G block instead of
60	// 3 × 25 = 75 G. Adjustment is applied to policy base for each component
61	// type with exactly 3 instances.
62	const COMPONENT_BLOCK_SIZE = 3;
63	const COMPONENT_BLOCK_PRICE = 60;
64	const COMPONENT_TYPES = ["rune", "moonstone"];
65	
66	function sumOver<T>(xs: T[], f: (x: T) => number): number {
67	  return xs.reduce((total, x) => total + f(x), 0);
68	}
69	
70	// MHPCO rounds quote premiums UP (in the office's favor).
71	function roundUpInFavorOfOffice(amount: number): number {
72	  return Math.ceil(amount);
73	}
74	
75	// MHPCO rounds claim payouts DOWN (in the office's favor) — symmetric
76	// counterpart of `roundUpInFavorOfOffice` for premiums.
77	function roundDownInFavorOfOffice(amount: number): number {
78	  return Math.floor(amount);
79	}
80	
81	function basePremium(type: string): number {
82	  return BASE_PREMIUM[type] ?? 0;
83	}
84	
85	function itemBasePremium(item: QuoteItem): number {
86	  return basePremium(item.type);
87	}
88	
89	// Per-type adjustment when exactly COMPONENT_BLOCK_SIZE items of `type` are
90	// present in the step: replace raw N × base with the flat block price.
91	function componentBlockAdjustment(items: QuoteItem[]): number {
92	  return sumOver(COMPONENT_TYPES, (type) => {
93	    const count = items.filter((x) => x.type === type).length;
94	    return count === COMPONENT_BLOCK_SIZE
95	      ? COMPONENT_BLOCK_PRICE - COMPONENT_BLOCK_SIZE * basePremium(type)
96	      : 0;
97	  });
98	}
99	
100	function itemSurcharges(item: QuoteItem): number {
101	  const base = itemBasePremium(item);
102	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
103	  const highEnchantmentSurcharge =
104	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
105	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
106	      : 0;
107	  return curseSurcharge + highEnchantmentSurcharge;
108	}
109	
110	function priceQuoteStep(
111	  step: QuoteStep,
112	  yearsWithMHPCO: number,
113	  isFollowUp: boolean,
114	): QuoteResult {
115	  const policyBase =
116	    sumOver(step.items, itemBasePremium) + componentBlockAdjustment(step.items);
117	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
118	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
119	  const loyaltyDiscount =
120	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
121	      ? policyBase * LOYALTY_DISCOUNT_RATE
122	      : 0;
123	  const followUpDiscount = isFollowUp
124	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
125	    : 0;
126	  const premium = roundUpInFavorOfOffice(
127	    policyBase +
128	      itemSurchargeTotal +
129	      firstInsurance -
130	      loyaltyDiscount -
131	      followUpDiscount +
132	      PROCESSING_FEE,
133	  );
134	  return { premium };
135	}
136	
137	const DEDUCTIBLE_PER_DAMAGE = 100;
138	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
139	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
140	
141	// Payout for a single damage entry: full reimbursement minus a flat
142	// per-damage deductible. Upcoming clauses (high-enchantment 50%,
143	// dragon-material) will compose here, mirroring how `itemSurcharges` is
144	// the home for per-item surcharges in `priceQuoteStep`.
145	function damagePayout(damage: DamageEntry, insuredItem: QuoteItem): number {
146	  const reimbursement =
147	    (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
148	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
149	      : damage.amount;
150	  return reimbursement - DEDUCTIBLE_PER_DAMAGE;
151	}
152	
153	// Resolves which insured item a damage entry refers to, by matching item
154	// type. Returns undefined if the damage's itemType isn't on the policy —
155	// upcoming validation tests (claim referencing item not in policy) will
156	// turn this into an explicit error path.
157	function insuredItemFor(
158	  damage: DamageEntry,
159	  policyItems: QuoteItem[],
160	): QuoteItem | undefined {
161	  return policyItems.find((item) => item.type === damage.itemType);
162	}
163	
164	function processClaimStep(step: ClaimStep, policyItems: QuoteItem[]): ClaimResult {
165	  const payout = roundDownInFavorOfOffice(
166	    sumOver(step.incident.damages, (damage) =>
167	      damagePayout(damage, insuredItemFor(damage, policyItems)!),
168	    ),
169	  );
170	  return { payout };
171	}
172	
173	// Validates that every item in a quote step has a known type. Throws a
174	// descriptive Error if not — the canonical home for quote-side input
175	// guards. Upcoming validation tests (negative amounts, etc.) should
176	// compose additional guards here.
177	function validateQuoteStep(step: QuoteStep): void {
178	  for (const item of step.items) {
179	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
180	      throw new Error(`Unknown item type: ${item.type}`);
181	    }
182	  }
183	}
184	
185	// Validates a claim step's damage entries. Throws a descriptive Error on
186	// any damage with a negative amount — the canonical home for claim-side
187	// input guards (will absorb future "unknown itemType in damage" and
188	// "more damages than insured" checks).
189	function validateClaimStep(step: ClaimStep, policyItems: QuoteItem[]): void {
190	  for (const damage of step.incident.damages) {
191	    if (damage.amount < 0) {
192	      throw new Error(`Negative damage amount: ${damage.amount}`);
193	    }
194	  }
195	  const damageCounts = new Map<string, number>();
196	  for (const damage of step.incident.damages) {
197	    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
198	  }
199	  for (const [itemType, damageCount] of damageCounts) {
200	    const insuredCount = policyItems.filter((x) => x.type === itemType).length;
201	    if (damageCount > insuredCount) {
202	      throw new Error(
203	        `More ${itemType} damages than insured: ${damageCount} > ${insuredCount}`,
204	      );
205	    }
206	  }
207	}
208	
209	export function runScenario(scenario: Scenario): {
210	  results: StepResult[];
211	} {
212	  const results = scenario.steps.map((step, index) => {
213	    if (step.op === "quote") {
214	      validateQuoteStep(step);
215	      return priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0);
216	    }
217	    const policyStep = scenario.steps[step.policy] as QuoteStep;
218	    validateClaimStep(step, policyStep.items);
219	    return processClaimStep(step, policyStep.items);
220	  });
221	  return { results };
222	}
